INSERT INTO products (id, category_id, name, description, price, stock_quantity, rating, num_reviews, specifications) VALUES
(260, 21, 'Nature Trust Wild Unprocessed Honey, 1.2 Kg', 'Pure raw honey, 100% natural with no preservatives, no artificial colour, no added sugar. Straight from wild honeycombs.', 699.00, 80, 4.6, 3200, '{"Weight": "1.2 Kg", "Type": "Raw Honey", "Brand": "Nature Trust", "Preservatives": "None"}'),
(261, 21, 'Eat Anytime Millet Energy Bar Assorted, 300gm (24 pcs)', 'Gluten-free, high-fibre energy bars made from millets. Sugar free, high protein – a healthy breakfast or snack option.', 499.00, 100, 4.4, 1800, '{"Weight": "300g", "Count": "24 bars x 25g", "Brand": "Eat Anytime", "Free From": "Gluten, Sugar"}'),
(262, 21, 'MTR Ready to Eat Mixed Vegetable Curry, 300g', 'Classic Indian mixed vegetable curry, ready in minutes. Just heat and eat. No preservatives.', 149.00, 200, 4.3, 4500, '{"Weight": "300g", "Type": "Ready to Eat", "Brand": "MTR", "Cuisine": "Indian"}'),
(263, 21, 'Lay''s Cream & Onion Potato Chips, 48g', 'America''s favourite cream & onion flavoured potato chips. Crispy, light and irresistibly snackable.', 30.00, 400, 4.5, 12000, '{"Weight": "48g", "Flavour": "Cream & Onion", "Brand": "Lay''s", "Type": "Potato Chips"}'),
(264, 21, 'Chef''s Basket Penne Pasta, 534g', 'Made with 100% Durum Wheat Semolina (Suji). No Maida. Rich in Protein & Fibre. Non-sticky and 100% vegetarian.', 199.00, 150, 4.5, 6700, '{"Weight": "534g", "Type": "Penne", "Brand": "Chef''s Basket", "Wheat": "100% Durum"}'),
(265, 21, 'Tata Sampann California Almonds/Badam, 500g', 'Real, whole California almonds. High in fibre, rich in Protein, Magnesium and Phosphorus. Premium quality dry fruit.', 599.00, 80, 4.7, 5400, '{"Weight": "500g", "Type": "Dry Fruit / Nut", "Brand": "Tata Sampann", "Origin": "California"}'),
(266, 21, 'Sunfeast Dark Fantasy Yumfills Whoopie Pie (Chocolate Chip), 253g', 'Soft and indulgent whoopie pies filled with rich chocolate chip cream. A premium biscuit treat.', 199.00, 150, 4.6, 8900, '{"Weight": "253g", "Flavour": "Chocolate Chip", "Brand": "Sunfeast Dark Fantasy", "Type": "Filled Biscuit"}'),
(267, 21, 'Del Monte Chifferi/Elbow Pasta, 1kg', 'Authentic Italian elbow pasta made with 100% Durum Wheat. No Maida, High Protein & Fibre, 0% Trans Fat. 100% Vegetarian.', 249.00, 120, 4.4, 3100, '{"Weight": "1kg", "Type": "Elbow/Chifferi", "Brand": "Del Monte", "Wheat": "100% Durum"}'),
(268, 21, 'Kitchens of India Murgh Methi, 285g (Ready to Eat)', 'ITC''s Murgh Methi in a rich, flavourful gravy. Microwavable. Just heat and eat – restaurant quality at home.', 199.00, 100, 4.4, 2300, '{"Weight": "285g", "Type": "Ready to Eat", "Brand": "Kitchens of India", "Cuisine": "North Indian"}'),
(269, 21, 'Tata Sampann Pure Cashews Whole/Kaju, 200g', 'Deluxe-size premium cashew nuts. Crunchy, nutritious and delicious. Rich in Protein, Magnesium & Phosphorus.', 249.00, 120, 4.7, 4100, '{"Weight": "200g", "Type": "Dry Fruit / Nut", "Brand": "Tata Sampann"}'),
(270, 21, 'Britannia NutriChoice Seeds Biscuits, 83.3g', '0% Maida & High Fibre biscuits loaded with nutritious seeds. A healthy, guilt-free snacking option.', 40.00, 300, 4.3, 5600, '{"Weight": "83.3g", "Type": "Health Biscuit", "Brand": "Britannia NutriChoice", "Free From": "Maida"}'),
(271, 21, 'Flyberry Gourmet Medjool Date & Dry Fruit Bites, 160g', 'Handmade date bites with Cashews, Almonds, Pista, Pumpkin Seeds, Oats & Pure Ghee. No added sugar. 6g Protein/serving.', 399.00, 70, 4.5, 1200, '{"Weight": "160g", "Brand": "Flyberry Gourmet", "Type": "Date Barfi / Energy Bite", "Sugar": "No Added Sugar"}'),
(272, 21, 'Farmley Berries Mix, 160g (8-in-1)', 'Healthy 8-in-1 berry snack mix with Cranberry, Black Raisins, Strawberry, Black Currant and more. Great for snacking.', 199.00, 100, 4.4, 890, '{"Weight": "160g", "Type": "Mixed Berries", "Brand": "Farmley", "Count": "8 Varieties"}'),
(273, 21, 'MTR Plain Upma Mix, 160g', 'Quick-make breakfast mix of roasted and seasoned semolina. Ready in minutes. Authentic South Indian taste.', 89.00, 250, 4.3, 3400, '{"Weight": "160g", "Type": "Breakfast Mix", "Brand": "MTR", "Cuisine": "South Indian"}'),
(274, 21, 'MTR 3 Minute Masala Upma, 60g Pouch', 'Instant upma – just add hot water. Spiced semolina with no added preservatives. A wholesome breakfast in 3 minutes.', 35.00, 350, 4.2, 4200, '{"Weight": "60g", "Type": "Instant Upma", "Brand": "MTR", "Prep Time": "3 Minutes"}'),
(275, 21, 'Chef''s Basket Fusilli Pasta, 534g', 'Spiral-shaped fusilli pasta made from 100% Durum Wheat Semolina. No Maida, non-sticky, vegetarian and high in protein.', 199.00, 140, 4.5, 5100, '{"Weight": "534g", "Type": "Fusilli", "Brand": "Chef''s Basket", "Wheat": "100% Durum"}'),
(276, 21, 'Kitchens of India Chicken Darbari, 285g (Ready to Eat)', 'ITC''s rich and aromatic Chicken Darbari curry. Microwavable, ready to eat – restaurant-style meal at home.', 229.00, 80, 4.5, 1900, '{"Weight": "285g", "Type": "Ready to Eat", "Brand": "Kitchens of India", "Cuisine": "Mughlai"}'),
(277, 21, 'The Baker''s Dozen Chocochip Cookies, 60g', 'Handmade cookies with generous chocolate chips. No preservatives, zero trans fat. Crunchy and rich in flavour.', 99.00, 150, 4.6, 3800, '{"Weight": "60g", "Type": "Cookies", "Brand": "The Baker''s Dozen", "Free From": "Preservatives, Trans Fat"}'),
(278, 21, 'Bauli Moonfills Strawberry Puff Roll, 45g', 'Soft and fluffy puff roll filled with sweet strawberry cream. A perfect on-the-go snack or lunchbox treat.', 30.00, 300, 4.1, 1500, '{"Weight": "45g", "Flavour": "Strawberry", "Brand": "Bauli Moonfills", "Type": "Puff Roll"}'),
(279, 21, 'Sunfeast Glucose Plus Biscuits, 1 Kg', 'Classic glucose biscuits for instant energy. Crispy, light and loved by all ages. A trusted everyday snack.', 115.00, 400, 4.4, 7600, '{"Weight": "1 Kg", "Type": "Glucose Biscuit", "Brand": "Sunfeast", "For": "All Ages"}');
